 }

+// AllowedMethods returns the set of HTTP methods registered for the given path pattern,
+// or an empty slice if the path is not found.
+func (r *DefaultRouter) AllowedMethods(path string) []string {
+	routes, err := r.routes.FilterByPath(path)
+	if err != nil {
+		return []string{}
+	}
+	methods := make([]string, 0, len(routes))
+	for _, ri := range routes {
+		if ri.Method != RouteNotFound && ri.Method != RouteAny {
+			methods = append(methods, ri.Method)
+		}
+	}
+	return methods
+}
